#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[200005]; scanf("%s",s);
        int ones=0; for(int i=0;i<N;i++) if(s[i]=='1') ones++;
        if(N%2==1 || ones%2==0) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

